#!/bin/bash
# bench.sh - Benchmark eo2lp proof verification
#
# Takes directories of .eo proof files (generated by gen-proofs.sh) and
# runs eo2lp encode + lambdapi check on each, collecting per-proof timing.
#
# Usage:
#   ./scripts/bench.sh <proofs-dir> [OPTIONS]
#   ./scripts/bench.sh proofs/QF_UF --max-lines 1000
#   ./scripts/bench.sh proofs/ --output bench_results/
#   ./scripts/bench.sh --summarize bench_results/

set -euo pipefail
export LC_NUMERIC=C

# ---------------------------------------------------------------------------
# Defaults
# ---------------------------------------------------------------------------

PROOFS_DIR=""
OUTPUT_DIR="bench_results"
ENCODE_TIMEOUT=120
BATCH_SIZE=200
MAX_LINES=0  # 0 = unlimited
SUMMARIZE_DIR=""
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_DIR="$(cd "$SCRIPT_DIR/.." && pwd)"

# ---------------------------------------------------------------------------
# Argument parsing
# ---------------------------------------------------------------------------

print_usage() {
  cat <<EOF
Usage: $(basename "$0") [OPTIONS] <proofs-dir>

Benchmark eo2lp proof verification on .eo proof files.

Arguments:
  proofs-dir               Directory containing .eo proof files

Options:
  --encode-timeout N       Seconds per eo2lp batch (default: $ENCODE_TIMEOUT)
  --batch-size N           Proofs per eo2lp batch (default: $BATCH_SIZE)
  --max-lines N            Skip proofs with more than N lines, 0=all (default: $MAX_LINES)
  --output DIR             Output directory (default: $OUTPUT_DIR)
  --summarize DIR          Print summary of existing results and exit
  -h, --help               Show this help
EOF
}

while [[ $# -gt 0 ]]; do
  case "$1" in
    --encode-timeout) ENCODE_TIMEOUT="$2"; shift 2 ;;
    --batch-size)  BATCH_SIZE="$2"; shift 2 ;;
    --max-lines)   MAX_LINES="$2"; shift 2 ;;
    --output)      OUTPUT_DIR="$2"; shift 2 ;;
    --summarize)   SUMMARIZE_DIR="$2"; shift 2 ;;
    -h|--help)     print_usage; exit 0 ;;
    -*)            echo "Unknown option: $1" >&2; print_usage; exit 1 ;;
    *)
      if [[ -z "$PROOFS_DIR" ]]; then
        PROOFS_DIR="$1"
      else
        echo "Unexpected argument: $1" >&2; print_usage; exit 1
      fi
      shift
      ;;
  esac
done

# ---------------------------------------------------------------------------
# Colors
# ---------------------------------------------------------------------------

if [[ -t 1 ]]; then
  RED='\033[31m'
  GREEN='\033[32m'
  YELLOW='\033[33m'
  DIM='\033[2m'
  BOLD='\033[1m'
  RESET='\033[0m'
else
  RED='' GREEN='' YELLOW='' DIM='' BOLD='' RESET=''
fi

log()  { echo -e "${DIM}[$(date +%H:%M:%S)]${RESET} $*"; }
pass() { echo -e "${GREEN}$*${RESET}"; }
fail() { echo -e "${RED}$*${RESET}"; }
warn() { echo -e "${YELLOW}$*${RESET}"; }

# ---------------------------------------------------------------------------
# Summarize mode (--summarize)
# ---------------------------------------------------------------------------

print_summary() {
  local dir="$1"
  local csv="$dir/results.csv"

  if [[ ! -f "$csv" ]]; then
    echo "No results found in $dir"
    return 1
  fi

  local stats
  stats=$(awk -F, '
    NR > 1 {
      total++
      if ($2 == "pass") { pass++; enc_sum += $3; chk_sum += $4; count++ }
      else if ($2 == "skip") skip++
      else if ($2 == "fail_encode") encfail++
      else if ($2 == "fail_check") chkfail++
    }
    END {
      avg_enc = (count > 0) ? enc_sum / count : 0
      avg_chk = (count > 0) ? chk_sum / count : 0
      printf "%d %d %d %d %d %.3f %.3f", \
        total, pass, skip, encfail, chkfail, avg_enc, avg_chk
    }
  ' "$csv")

  read -r total pass skip encfail chkfail avg_enc avg_chk <<< "$stats"

  echo ""
  printf "${BOLD}Results: %s${RESET}\n" "$csv"
  printf '%0.s─' {1..50}; echo
  printf "  Total:        %6d\n" "$total"
  printf "  ${GREEN}Pass:         %6d${RESET}\n" "$pass"
  if [[ "$skip" -gt 0 ]]; then
    printf "  ${YELLOW}Skip:         %6d${RESET}\n" "$skip"
  fi
  if [[ "$encfail" -gt 0 ]]; then
    printf "  ${RED}Encode fail:  %6d${RESET}\n" "$encfail"
  fi
  if [[ "$chkfail" -gt 0 ]]; then
    printf "  ${RED}Check fail:   %6d${RESET}\n" "$chkfail"
  fi
  if [[ "$pass" -gt 0 ]]; then
    printf "  Avg encode:  %7.3fs\n" "$avg_enc"
    printf "  Avg check:   %7.3fs\n" "$avg_chk"
  fi

  # Error category breakdown
  local has_errors=$(( encfail + chkfail ))
  if [[ "$has_errors" -gt 0 ]]; then
    printf "\n  ${BOLD}Error categories:${RESET}\n"
    awk -F, 'NR > 1 && $6 != "" { cats[$6]++ }
      END { for (c in cats) printf "    %-20s %d\n", c, cats[c] }' "$csv" | sort -t' ' -k2 -rn
  fi

  printf '%0.s─' {1..50}; echo
  echo ""
}

if [[ -n "$SUMMARIZE_DIR" ]]; then
  print_summary "$SUMMARIZE_DIR"
  exit 0
fi

# ---------------------------------------------------------------------------
# Pre-flight checks
# ---------------------------------------------------------------------------

if [[ -z "$PROOFS_DIR" ]]; then
  echo "Error: specify a proofs directory or --summarize" >&2
  print_usage
  exit 1
fi

if [[ ! -d "$PROOFS_DIR" ]]; then
  echo "Error: proofs directory not found: $PROOFS_DIR" >&2
  exit 1
fi

if ! command -v dune &>/dev/null; then
  echo "Error: dune not found in PATH" >&2
  exit 1
fi

# ---------------------------------------------------------------------------
# Encode and check proofs with eo2lp
# ---------------------------------------------------------------------------

encode_and_check() {
  local proof_dir="$1"

  # Collect .eo files, optionally filtering by line count
  local all_proofs
  all_proofs=$(find "$proof_dir" -name '*.eo' -type f | sort)

  if [[ -z "$all_proofs" ]]; then
    log "No .eo files found in $proof_dir"
    return
  fi

  local proof_list
  proof_list=$(mktemp)
  local n_total=0 n_skip=0

  while IFS= read -r f; do
    n_total=$((n_total + 1))
    if [[ "$MAX_LINES" -gt 0 ]]; then
      local lines
      lines=$(wc -l < "$f")
      if [[ "$lines" -gt "$MAX_LINES" ]]; then
        n_skip=$((n_skip + 1))
        local bn
        bn=$(basename "$f" .eo)
        echo "$bn,skip,,,,$lines,proof too large (${lines} lines)" >> "$OUTPUT_DIR/skipped.csv"
        continue
      fi
    fi
    echo "$f" >> "$proof_list"
  done <<< "$all_proofs"

  local n_proofs
  n_proofs=$(wc -l < "$proof_list")

  if [[ "$n_skip" -gt 0 ]]; then
    log "Skipped $n_skip/$n_total proofs exceeding $MAX_LINES lines"
  fi

  if [[ "$n_proofs" -eq 0 ]]; then
    log "No proofs to encode after filtering"
    rm -f "$proof_list"
    return
  fi

  log "Encoding and checking $n_proofs proofs"

  # Split into batches
  local batch_num=0
  local batch_total=$(( (n_proofs + BATCH_SIZE - 1) / BATCH_SIZE ))

  local offset=0
  while [[ $offset -lt $n_proofs ]]; do
    batch_num=$((batch_num + 1))
    local batch_dir
    batch_dir=$(mktemp -d)

    # Copy this batch of .eo files
    sed -n "$((offset + 1)),$((offset + BATCH_SIZE))p" "$proof_list" | while IFS= read -r f; do
      [[ -n "$f" && -f "$f" ]] && cp "$f" "$batch_dir/"
    done

    local batch_count
    batch_count=$(find "$batch_dir" -name '*.eo' | wc -l)
    if [[ "$batch_count" -eq 0 ]]; then
      rm -rf "$batch_dir"
      offset=$((offset + BATCH_SIZE))
      continue
    fi

    if [[ "$batch_total" -gt 1 ]]; then
      log "  batch $batch_num/$batch_total ($batch_count proofs)"
    fi

    # Run eo2lp with --proofs-only (loads pre-built CPC, encodes+checks proofs)
    local eo2lp_output
    eo2lp_output=$(cd "$PROJECT_DIR" && timeout "$ENCODE_TIMEOUT" \
      dune exec eo2lp -- -d ./cpc -o "$OUTPUT_DIR/cpc" --proofs "$batch_dir" --proofs-only --no-color 2>&1) || true

    # Log eo2lp summary lines
    echo "$eo2lp_output" | grep -E 'encoding.*proofs|checking.*proofs' | while IFS= read -r line; do
      log "  $line"
    done

    # Parse per-proof timing lines and capture error details
    echo "$eo2lp_output" | grep '^ *proof: ' | while IFS= read -r line; do
      local pname pphase pstatus ptime perror
      pname=$(echo "$line" | awk '{print $2}')
      pphase=$(echo "$line" | awk '{print $3}')
      pstatus=$(echo "$line" | awk '{print $4}')
      ptime=$(echo "$line" | awk '{print $5}' | sed 's/ms//')
      # Capture error message (everything after the timing field)
      perror=$(echo "$line" | sed 's/^ *proof: [^ ]* [^ ]* [^ ]* [^ ]* *//')

      echo "$pname,$pphase,$pstatus,$ptime,$perror" >> "$OUTPUT_DIR/timing.log"
    done

    rm -rf "$batch_dir"
    offset=$((offset + BATCH_SIZE))
  done
  rm -f "$proof_list"
}

# ---------------------------------------------------------------------------
# Write results CSV
# ---------------------------------------------------------------------------

classify_error() {
  local error_msg="$1"
  case "$error_msg" in
    *"parse error"*|*"Parse error"*)       echo "parse_error" ;;
    *"pop_assumption"*|*"assumption stack"*) echo "stack_error" ;;
    *"not found"*|*"Not_found"*)            echo "symbol_not_found" ;;
    *"Cannot infer"*|*"infer_noexn"*)       echo "type_inference" ;;
    *"not in context"*)                     echo "context_error" ;;
    *"ghost"*|*"rational"*|*"string"*)      echo "unsupported_literal" ;;
    *"premise"*)                            echo "premise_error" ;;
    *"Subject"*|*"subject"*)                echo "sr_failure" ;;
    *"Typ"*|*"typ"*|*"type"*)              echo "type_error" ;;
    *)                                      echo "other" ;;
  esac
}

write_results() {
  local csv="$OUTPUT_DIR/results.csv"
  echo "file,status,encode_time,check_time,lines,error_category,error" > "$csv"

  if [[ ! -f "$OUTPUT_DIR/timing.log" ]]; then
    # No timing data — only skipped proofs
    if [[ -f "$OUTPUT_DIR/skipped.csv" ]]; then
      cat "$OUTPUT_DIR/skipped.csv" >> "$csv"
    fi
    return
  fi

  # Collect unique proof names from timing log
  local names
  names=$(awk -F, '{print $1}' "$OUTPUT_DIR/timing.log" | sort -u)

  while IFS= read -r name; do
    [[ -z "$name" ]] && continue

    local enc_ms chk_ms enc_status chk_status enc_error chk_error
    enc_ms=$(grep "^${name},encode," "$OUTPUT_DIR/timing.log" | tail -1 | cut -d, -f4 || true)
    chk_ms=$(grep "^${name},check," "$OUTPUT_DIR/timing.log" | tail -1 | cut -d, -f4 || true)
    enc_status=$(grep "^${name},encode," "$OUTPUT_DIR/timing.log" | tail -1 | cut -d, -f3 || true)
    chk_status=$(grep "^${name},check," "$OUTPUT_DIR/timing.log" | tail -1 | cut -d, -f3 || true)
    enc_error=$(grep "^${name},encode," "$OUTPUT_DIR/timing.log" | tail -1 | cut -d, -f5- || true)
    chk_error=$(grep "^${name},check," "$OUTPUT_DIR/timing.log" | tail -1 | cut -d, -f5- || true)

    local enc_sec="" chk_sec=""
    [[ -n "$enc_ms" ]] && enc_sec=$(awk "BEGIN{printf \"%.3f\", $enc_ms / 1000}")
    [[ -n "$chk_ms" ]] && chk_sec=$(awk "BEGIN{printf \"%.3f\", $chk_ms / 1000}")

    # Determine overall status and error category
    local status="pass"
    local error=""
    local error_cat=""
    if [[ "$enc_status" == "error" ]]; then
      status="fail_encode"
      error="$enc_error"
      error_cat=$(classify_error "$error")
    elif [[ "$chk_status" == "error" ]]; then
      status="fail_check"
      error="$chk_error"
      error_cat=$(classify_error "$error")
    fi

    # Get line count from the .eo file
    local lines=""
    local eo_file
    eo_file=$(find "$PROOFS_DIR" -name "${name}.eo" -type f 2>/dev/null | head -1)
    [[ -n "$eo_file" ]] && lines=$(wc -l < "$eo_file")

    echo "${name},${status},${enc_sec},${chk_sec},${lines},${error_cat},${error}" >> "$csv"
  done <<< "$names"

  # Append skipped proofs
  if [[ -f "$OUTPUT_DIR/skipped.csv" ]]; then
    cat "$OUTPUT_DIR/skipped.csv" >> "$csv"
  fi
}

# ---------------------------------------------------------------------------
# Main
# ---------------------------------------------------------------------------

main() {
  local t_start
  t_start=$(date +%s)

  log "${BOLD}eo2lp benchmark${RESET}"
  log "proofs: $PROOFS_DIR"
  log "config: encode_timeout=${ENCODE_TIMEOUT}s batch_size=$BATCH_SIZE max_lines=$MAX_LINES"
  log "output: $OUTPUT_DIR"
  echo

  # Setup output directories
  mkdir -p "$OUTPUT_DIR"
  rm -f "$OUTPUT_DIR/timing.log" "$OUTPUT_DIR/skipped.csv"

  # Build CPC once
  log "Building CPC encoding..."
  local cpc_output
  cpc_output=$(cd "$PROJECT_DIR" && dune exec eo2lp -- -o "$OUTPUT_DIR/cpc" --no-color 2>&1)
  if echo "$cpc_output" | grep -q "failed"; then
    fail "CPC build failed:"
    echo "$cpc_output"
    exit 1
  fi
  local cpc_status
  cpc_status=$(echo "$cpc_output" | tail -1)
  log "CPC: $cpc_status"
  echo

  # Encode and check proofs
  encode_and_check "$PROOFS_DIR"
  echo

  # Write results
  write_results

  # Print summary
  print_summary "$OUTPUT_DIR"

  local t_end
  t_end=$(date +%s)
  local elapsed=$((t_end - t_start))
  log "Total wall time: ${elapsed}s"
}

main
